// WORKSTATE ??applier-log 遺덉씪移섎? ?먯??섎뒗 ?대? reconciliation 寃?ш린.
// CLI ?쒕㈃ 誘몃끂異???HarnessRegistry 誘몃벑濡? StateApplierCli in-process ?몄텧 ?꾩슜.
using System.Text.Json;
using System.Text.Json.Nodes;

// in-process ?몄텧 ?듭뀡. PendingTransitionId媛 ?덉쑝硫?state-only 1??硫댁젣瑜??곸슜?쒕떎.
internal record ReconciliationOptions(
    string WorkstatePath,
    string ApplierLogPath,
    string? PendingTransitionId = null
);

// 媛쒕퀎 log ??ぉ ?뚯떛 寃곌낵.
internal record LogEntry(
    string TransitionId,
    string Result,
    int ExitCode,
    string At,
    int SchemaVersion,
    string? TransitionContractSha256
);

// lookupSuccess 諛섑솚媛???06C-1 idempotency ?먯젙??
internal record LogLookupResult(bool Exists, int SchemaVersion, string? TransitionContractSha256);

// reconciliation 寃???⑥씪 ??ぉ.
internal record ReconciliationEntry(string Subject, string Code, string Message);

// reconciliation 吏????JSON 吏곷젹?붿슜.
internal record ReconciliationMetrics(
    int AppliedTransitionCount,
    int SuccessfulLogEntryCount,
    int SuccessfulLogIdCount,
    int DuplicateSuccessLogCount,
    Dictionary<string, int> LogSchemaVersions,
    bool PendingExemptionApplied,
    string Reconciliation
);

internal class ReconciliationResult
{
    public List<ReconciliationEntry> Failures { get; } = [];
    public List<ReconciliationEntry> Warnings { get; } = [];
    public List<ReconciliationEntry> HarnessErrors { get; } = [];
    public ReconciliationMetrics? Metrics { get; set; }
    // 06C-1 idempotency ?먯젙??lookup. ?깃났 log?먯꽌留?諛섑솚.
    public Dictionary<string, LogLookupResult> SuccessLookup { get; } = [];
}

internal static class HandoffIntegrityChecker
{
    private static readonly HashSet<string> AllowedTransitionKinds =
        new(StringComparer.OrdinalIgnoreCase) { "NORMAL", "RECOVERY", "PHASE_CHANGE", "REPLAY" };

    // WORKSTATE appliedTransitions ??applier-log.jsonl 遺덉씪移섎? 寃?ы븳??
    internal static ReconciliationResult Run(ReconciliationOptions opts)
    {
        var result = new ReconciliationResult();

        var (workstate, wsErr) = LoadWorkstate(opts.WorkstatePath);
        if (wsErr != null) { result.HarnessErrors.Add(wsErr); return result; }

        var (stateIds, transErr) = ParseAppliedTransitions(workstate!);
        if (transErr != null) { result.HarnessErrors.Add(transErr); return result; }

        var (logEntries, logErr) = ParseApplierLog(opts.ApplierLogPath);
        if (logErr != null) { result.HarnessErrors.Add(logErr); return result; }

        var sets = BuildSets(stateIds!, logEntries!);
        CheckDuplicatesInState(stateIds!, result);
        CheckDuplicateSuccessLog(sets.successCounts, result);
        CheckLogToState(sets.successfulLogIdSet, sets.stateIdSet, result);
        var pendingApplied = CheckStateToLog(sets.stateIdSet, sets.successfulLogIdSet, sets.allLogIdSet, stateIds!, opts.PendingTransitionId, result);
        BuildLookup(sets.successfulLogIdSet, sets.successCounts, result);
        result.Metrics = BuildMetrics(stateIds!, logEntries!, sets, pendingApplied, result);
        return result;
    }

    // WORKSTATE.json???뚯떛?쒕떎. ?ㅽ뙣 ??HarnessError 諛섑솚.
    private static (JsonObject? ws, ReconciliationEntry? err) LoadWorkstate(string path)
    {
        try
        {
            var ws = JsonNode.Parse(File.ReadAllText(path)) as JsonObject;
            return ws is null
                ? (null, H("workstate", "workstate-malformed", "WORKSTATE is not a JSON object"))
                : (ws, null);
        }
        catch (Exception ex)
        {
            return (null, H("workstate", "workstate-malformed", ex.Message));
        }
    }

    // appliedTransitions 諛곗뿴???뚯떛??id 紐⑸줉??諛섑솚?쒕떎.
    private static (List<string>? ids, ReconciliationEntry? err) ParseAppliedTransitions(JsonObject ws)
    {
        if (ws["appliedTransitions"] is not JsonArray arr)
            return (null, H("workstate.appliedTransitions", "workstate-malformed",
                "appliedTransitions is missing or not an array"));

        var ids = new List<string>();
        foreach (var node in arr)
        {
            if (node is not JsonObject elem)
                return (null, H("workstate.appliedTransitions", "workstate-malformed",
                    "appliedTransitions element is not an object"));

            var id = elem["id"]?.GetValue<string>() ?? "";
            if (string.IsNullOrWhiteSpace(id))
                return (null, H("workstate.appliedTransitions", "workstate-malformed",
                    "appliedTransitions element has missing or empty id"));

            var appliedAt = elem["appliedAt"]?.GetValue<string>() ?? "";
            if (!IsValidUtcRfc3339(appliedAt))
                return (null, H($"workstate.appliedTransitions[{id}].appliedAt",
                    "workstate-malformed",
                    $"appliedAt is missing or not a valid UTC RFC3339 timestamp: '{appliedAt}'"));

            ids.Add(id);
        }
        return (ids, null);
    }

    // applier-log.jsonl???뚯떛??LogEntry 紐⑸줉??諛섑솚?쒕떎.
    private static (List<LogEntry>? entries, ReconciliationEntry? err) ParseApplierLog(string path)
    {
        if (!File.Exists(path))
            return (null, H("applier-log", "applier-log-malformed", $"applier-log not found: {path}"));

        var entries = new List<LogEntry>();
        foreach (var line in File.ReadLines(path))
        {
            var trimmed = line.Trim();
            if (string.IsNullOrEmpty(trimmed)) continue;

            var (entry, err) = ParseLogLine(trimmed);
            if (err != null) return (null, err);
            entries.Add(entry!);
        }
        return (entries, null);
    }

    // log 1以꾩쓣 ?뚯떛?쒕떎. ?ㅻ쪟 ??null entry + ReconciliationEntry error 諛섑솚.
    private static (LogEntry? entry, ReconciliationEntry? err) ParseLogLine(string trimmed)
    {
        JsonObject row;
        try { row = JsonNode.Parse(trimmed) as JsonObject ?? throw new InvalidOperationException("not object"); }
        catch (Exception ex)
            { return (null, H("applier-log", "applier-log-malformed", $"log line not valid JSON: {ex.Message}")); }

        var tid = row["transitionId"]?.GetValue<string>() ?? "";
        if (string.IsNullOrWhiteSpace(tid))
            return (null, H("applier-log.transitionId", "applier-log-malformed", "transitionId missing or empty"));

        var res = row["result"];
        if (res is null || res.GetValueKind() != JsonValueKind.String)
            return (null, H($"applier-log[{tid}].result", "applier-log-malformed", "result missing or not string"));

        int exitCode;
        try { exitCode = row["exitCode"]?.GetValue<int>() ?? throw new InvalidOperationException("missing"); }
        catch { return (null, H($"applier-log[{tid}].exitCode", "applier-log-malformed", "exitCode missing or not integer")); }

        var at = row["at"]?.GetValue<string>() ?? "";
        if (!IsValidUtcRfc3339(at))
            return (null, H($"applier-log[{tid}].at", "applier-log-malformed", $"at invalid: '{at}'"));

        int sv = 1;
        if (row["schemaVersion"] is { } svNode && int.TryParse(svNode.ToString(), out var p)) sv = p;

        string? contractHash = null;
        if (sv >= 2)
        {
            var err = ValidateV2Fields(row, tid);
            if (err != null) return (null, H($"applier-log[{tid}]", "applier-log-malformed", err));
            contractHash = row["transitionContractSha256"]?.GetValue<string>();
        }

        return (new LogEntry(tid, res.GetValue<string>(), exitCode, at, sv, contractHash), null);
    }

    // 吏묓빀 援ъ“泥대? 議곕┰?쒕떎.
    private static (HashSet<string> stateIdSet, HashSet<string> successfulLogIdSet,
        HashSet<string> allLogIdSet, Dictionary<string, List<LogEntry>> successCounts)
        BuildSets(List<string> stateIds, List<LogEntry> logEntries)
    {
        var stateIdSet = new HashSet<string>(stateIds, StringComparer.Ordinal);
        var allLogIdSet = new HashSet<string>(logEntries.Select(e => e.TransitionId), StringComparer.Ordinal);
        var successfulEntries = logEntries
            .Where(e => string.Equals(e.Result, "ok", StringComparison.OrdinalIgnoreCase) && e.ExitCode == 0);
        var successfulLogIdSet = new HashSet<string>(
            successfulEntries.Select(e => e.TransitionId), StringComparer.Ordinal);
        var successCounts = successfulEntries
            .GroupBy(e => e.TransitionId, StringComparer.Ordinal)
            .ToDictionary(g => g.Key, g => g.ToList(), StringComparer.Ordinal);
        return (stateIdSet, successfulLogIdSet, allLogIdSet, successCounts);
    }

    // state ??以묐났 id瑜??먯??쒕떎.
    private static void CheckDuplicatesInState(List<string> stateIds, ReconciliationResult result)
    {
        var seen = new HashSet<string>(StringComparer.Ordinal);
        foreach (var id in stateIds)
            if (!seen.Add(id))
                result.Failures.Add(F(id, "duplicate-in-state",
                    $"transition id '{id}' appears more than once in appliedTransitions"));
    }

    // log ??以묐났 ?깃났 ??ぉ???먯??쒕떎. contract hash 異⑸룎? Failure, 媛숈? hash??Warning.
    private static void CheckDuplicateSuccessLog(
        Dictionary<string, List<LogEntry>> successCounts, ReconciliationResult result)
    {
        foreach (var (id, entries) in successCounts.Where(kv => kv.Value.Count > 1))
        {
            var hasContract = entries.All(e => !string.IsNullOrEmpty(e.TransitionContractSha256));
            if (hasContract)
            {
                var distinct = entries.Select(e => e.TransitionContractSha256!)
                    .Distinct(StringComparer.OrdinalIgnoreCase).ToList();
                if (distinct.Count > 1)
                    result.Failures.Add(F(id, "duplicate-success-log-conflict",
                        $"id '{id}' has {entries.Count} success entries with differing transitionContractSha256"));
                else
                    result.Warnings.Add(W(id, "duplicate-success-in-log",
                        $"id '{id}' appears {entries.Count} times (same contract ??append-only replay)"));
            }
            else
            {
                result.Warnings.Add(W(id, "duplicate-success-in-log",
                    $"id '{id}' appears {entries.Count} times (v1 entries, contract binding unverifiable)"));
            }
        }
    }

    // 洹쒖튃 1: successfulLogIdSet ??stateIdSet. log ?깃났 ??ぉ??state???놁쑝硫?Failure.
    private static void CheckLogToState(
        HashSet<string> successfulLogIdSet, HashSet<string> stateIdSet, ReconciliationResult result)
    {
        foreach (var id in successfulLogIdSet)
            if (!stateIdSet.Contains(id))
                result.Failures.Add(F(id, "log-transition-missing-from-state",
                    $"id '{id}' is in successful log but missing from appliedTransitions (mid-incident state)"));
    }

    // 洹쒖튃 2: stateIdSet ??successfulLogIdSet. state ??ぉ???깃났 log???놁쑝硫?Failure. PendingTransitionId 1??硫댁젣(log???대뼡 ??ぉ???놁쓣 ?뚮쭔).
    private static bool CheckStateToLog(
        HashSet<string> stateIdSet, HashSet<string> successfulLogIdSet,
        HashSet<string> allLogIdSet, List<string> stateIds, string? pendingId, ReconciliationResult result)
    {
        var pendingApplied = false;
        foreach (var id in stateIdSet)
        {
            if (successfulLogIdSet.Contains(id)) continue;
            if (!string.IsNullOrEmpty(pendingId)
                && string.Equals(id, pendingId, StringComparison.Ordinal)
                && stateIds.Count(s => string.Equals(s, id, StringComparison.Ordinal)) == 1
                && !allLogIdSet.Contains(id))
            {
                pendingApplied = true;
                continue;
            }
            result.Failures.Add(F(id, "state-transition-not-logged",
                $"id '{id}' is in appliedTransitions but has no successful log entry"));
        }
        return pendingApplied;
    }

    // 06C-1 idempotency ?먯젙???꾪븳 lookupSuccess ?ъ쟾??梨꾩슫??
    private static void BuildLookup(
        HashSet<string> successfulLogIdSet,
        Dictionary<string, List<LogEntry>> successCounts,
        ReconciliationResult result)
    {
        foreach (var id in successfulLogIdSet)
        {
            var best = successCounts.GetValueOrDefault(id)?.FirstOrDefault();
            if (best is not null)
                result.SuccessLookup[id] = new LogLookupResult(true, best.SchemaVersion, best.TransitionContractSha256);
        }
    }

    // 吏??媛앹껜瑜?議곕┰?쒕떎.
    private static ReconciliationMetrics BuildMetrics(
        List<string> stateIds, List<LogEntry> logEntries,
        (HashSet<string> stateIdSet, HashSet<string> successfulLogIdSet,
         HashSet<string> allLogIdSet, Dictionary<string, List<LogEntry>> successCounts) sets,
        bool pendingApplied, ReconciliationResult result)
    {
        var successfulEntries = logEntries
            .Where(e => string.Equals(e.Result, "ok", StringComparison.OrdinalIgnoreCase) && e.ExitCode == 0)
            .ToList();
        var schemaVersions = logEntries
            .GroupBy(e => $"v{e.SchemaVersion}")
            .ToDictionary(g => g.Key, g => g.Count());
        var dupCount = sets.successCounts.Values.Count(v => v.Count > 1);
        var allClear = result.Failures.Count == 0 && result.HarnessErrors.Count == 0;
        return new ReconciliationMetrics(
            AppliedTransitionCount: stateIds.Count,
            SuccessfulLogEntryCount: successfulEntries.Count,
            SuccessfulLogIdCount: sets.successfulLogIdSet.Count,
            DuplicateSuccessLogCount: dupCount,
            LogSchemaVersions: schemaVersions,
            PendingExemptionApplied: pendingApplied,
            Reconciliation: allClear ? "PASS" : "FAIL"
        );
    }

    // v2 log ??ぉ???꾩닔 ?꾨뱶瑜?寃利앺븳?? ?ㅻ쪟 硫붿떆吏瑜?諛섑솚?섍퀬 ?뺤긽?대㈃ null.
    private static string? ValidateV2Fields(JsonObject row, string tid)
    {
        var kind = row["transitionKind"]?.GetValue<string>() ?? "";
        if (!AllowedTransitionKinds.Contains(kind))
            return $"transitionKind missing or invalid (got '{kind}')";

        foreach (var field in new[] { "requestSha256", "preStateSha256", "postStateSha256", "transitionContractSha256" })
        {
            var val = row[field]?.GetValue<string>() ?? "";
            if (!Is64Hex(val)) return $"{field} missing or not 64-char hex";
        }

        var effectiveAt = row["effectiveAt"]?.GetValue<string>() ?? "";
        if (!IsValidUtcRfc3339(effectiveAt)) return $"effectiveAt invalid: '{effectiveAt}'";
        return null;
    }

    // 64??16吏꾩닔 臾몄옄?댁씤吏 ?뺤씤?쒕떎.
    private static bool Is64Hex(string? s)
        => s is { Length: 64 } && s.All(c =>
            (c >= '0' && c <= '9') || (c >= 'a' && c <= 'f') || (c >= 'A' && c <= 'F'));

    // UTC RFC3339 ??꾩뒪?ы봽 ?뺤떇?몄? ?뺤씤?쒕떎.
    private static bool IsValidUtcRfc3339(string? s)
    {
        if (string.IsNullOrWhiteSpace(s)) return false;
        return DateTimeOffset.TryParse(s,
            System.Globalization.CultureInfo.InvariantCulture,
            System.Globalization.DateTimeStyles.RoundtripKind, out _);
    }

    // ?ㅽ뙣 ??ぉ??留뚮뱺??
    private static ReconciliationEntry F(string s, string c, string m) => new(s, c, m);
    // 寃쎄퀬 ??ぉ??留뚮뱺??
    private static ReconciliationEntry W(string s, string c, string m) => new(s, c, m);
    // ?섎꽕???ㅻ쪟 ??ぉ??留뚮뱺??
    private static ReconciliationEntry H(string s, string c, string m) => new(s, c, m);
}

// WORKSTATE handoff integrity harness.
// Checks that the current handoff record is backed by real files, hashes, and completion artifacts.
// --workstate + --applier-log ????吏????fixture 寃⑸━ 紐⑤뱶: reconciliation+malformed+blockers留??ㅽ뻾.
using System.Security.Cryptography;
using System.Text.Encodings.Web;
using System.Text.Json;
using System.Text.Json.Nodes;

internal static class HandoffIntegrityCli
{
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        WriteIndented = true,
        Encoder = JavaScriptEncoder.UnsafeRelaxedJsonEscaping,
    };

    private static readonly HashSet<string> DoneStatuses = new(StringComparer.OrdinalIgnoreCase)
    {
        "done", "completed", "complete", "pass", "passed",
    };

    // handoff-integrity entry. exit 0=integrity verified, 1=contract gap, 2=harness error.
    internal static int Run(string[] args)
    {
        try
        {
            if (args.Any(a => string.Equals(a, "--pending-transition", StringComparison.OrdinalIgnoreCase)))
            {
                Console.Error.WriteLine("{\"error\":\"pending-not-allowed-on-cli\",\"code\":\"pending-not-allowed-on-cli\"}");
                return 1;
            }
            var root = GitTools.FindRepoRoot();
            if (args.Any(a => string.Equals(a, "--self-test", StringComparison.OrdinalIgnoreCase)))
                return RunSelfTest(root);
            var (workstatePath, applierLogPath, fixtureMode) = ParsePaths(args, root);
            if (!File.Exists(workstatePath))
                { Console.Error.WriteLine("{\"error\":\"WORKSTATE.json not found\"}"); return 2; }
            var parsed = JsonNode.Parse(File.ReadAllText(workstatePath)) as JsonObject;
            if (parsed is null)
                { Console.Error.WriteLine("{\"error\":\"WORKSTATE.json is not a JSON object\"}"); return 2; }
            return RunChecks(root, parsed, workstatePath, applierLogPath, fixtureMode);
        }
        catch (Exception ex)
        {
            Console.Error.WriteLine($"{{\"error\":\"handoff-integrity failed: {ex.Message}\"}}");
            return 2;
        }
    }

    // --workstate / --applier-log ?몄옄瑜??뚯떛???덈? 寃쎈줈? 紐⑤뱶瑜?諛섑솚?쒕떎.
    private static (string workstatePath, string applierLogPath, bool fixtureMode) ParsePaths(string[] args, string root)
    {
        string? workstateArg = null;
        string? applierLogArg = null;
        for (int i = 1; i < args.Length; i++)
        {
            if (string.Equals(args[i], "--workstate", StringComparison.OrdinalIgnoreCase) && i + 1 < args.Length)
                workstateArg = args[++i];
            else if (string.Equals(args[i], "--applier-log", StringComparison.OrdinalIgnoreCase) && i + 1 < args.Length)
                applierLogArg = args[++i];
            else if (workstateArg is null && !args[i].StartsWith("--"))
                workstateArg = args[i];
        }
        var wsPath = workstateArg is not null
            ? Path.GetFullPath(Path.IsPathRooted(workstateArg) ? workstateArg : Path.Combine(root, workstateArg))
            : Path.Combine(root, "docs", "handoff", "WORKSTATE.json");
        var logPath = applierLogArg is not null
            ? Path.GetFullPath(Path.IsPathRooted(applierLogArg) ? applierLogArg : Path.Combine(root, applierLogArg))
            : Path.Combine(root, "docs", "handoff", "WORKSTATE.applier-log.jsonl");
        return (wsPath, logPath, applierLogArg is not null);
    }

    // 紐⑤뱺 寃?щ? ?ㅽ뻾?섍퀬 蹂닿퀬?쒕? 異쒕젰?쒕떎.
    private static int RunChecks(
        string root, JsonObject parsed, string workstatePath, string applierLogPath, bool fixtureMode)
    {
        var failures = new JsonArray();
        var warnings = new JsonArray();
        var changedFiles = new JsonArray();
        var diId = ReadString(parsed, "diId");
        var status = ReadString(parsed, "status");

        var reconc = RunReconciliation(workstatePath, applierLogPath, failures, warnings);
        if (reconc.harnessErrors > 0)
        {
            Console.WriteLine(new JsonObject
            {
                ["harness"] = "handoff-integrity",
                ["workstate"] = Path.GetRelativePath(root, workstatePath).Replace('\\', '/'),
                ["fixtureMode"] = fixtureMode,
                ["verdict"] = "HARNESS_ERROR",
                ["failures"] = failures, ["warnings"] = warnings,
            }.ToJsonString(JsonOptions));
            return 2;
        }

        if (!fixtureMode)
            RunFullModeChecks(root, parsed, diId, status, failures, warnings, changedFiles);
        CheckBlockerConsistency(parsed, status, failures);

        Console.WriteLine(new JsonObject
        {
            ["harness"] = "handoff-integrity",
            ["workstate"] = Path.GetRelativePath(root, workstatePath).Replace('\\', '/'),
            ["applierLog"] = Path.GetRelativePath(root, applierLogPath).Replace('\\', '/'),
            ["fixtureMode"] = fixtureMode,
            ["diId"] = diId, ["status"] = status,
            ["changedFileCount"] = changedFiles.Count,
            ["failureCount"] = failures.Count, ["warningCount"] = warnings.Count,
            ["verdict"] = failures.Count == 0 ? "PASS" : "FAIL",
            ["reconciliation"] = reconc.reconciliationResult,
            ["changedFiles"] = changedFiles, ["failures"] = failures, ["warnings"] = warnings,
            ["note"] = fixtureMode
                ? "Fixture isolation mode: reconciliation+blockers only."
                : "Full mode: changedFiles hash, completion, queue, reconciliation.",
        }.ToJsonString(JsonOptions));
        return failures.Count == 0 ? 0 : 1;
    }

    // full 紐⑤뱶?먯꽌 changedFiles쨌completion쨌queue瑜?寃?ы븳??
    private static void RunFullModeChecks(
        string root, JsonObject parsed, string diId, string status,
        JsonArray failures, JsonArray warnings, JsonArray changedFiles)
    {
        CheckRequired(parsed, "schemaVersion", failures);
        CheckRequired(parsed, "diId", failures);
        CheckRequired(parsed, "status", failures);
        var changed = parsed["changedFiles"] as JsonArray;
        if (changed is null || changed.Count == 0)
            failures.Add(Failure("changedFiles", "missing", "changedFiles must be a non-empty array"));
        else
            foreach (var item in changed.OfType<JsonObject>())
                changedFiles.Add(CheckChangedFile(root, item, failures));
        CheckCompletionArtifacts(root, parsed, diId, status, failures, warnings);
        CheckQueueStatus(root, diId, status, failures, warnings);
    }

    // HandoffIntegrityChecker瑜??ㅽ뻾?섍퀬 寃곌낵瑜?failures/warnings??蹂묓빀?쒕떎.
    private static (int harnessErrors, JsonNode? reconciliationResult) RunReconciliation(
        string workstatePath, string applierLogPath,
        JsonArray failures, JsonArray warnings)
    {
        var opts = new ReconciliationOptions(workstatePath, applierLogPath, null);
        var result = HandoffIntegrityChecker.Run(opts);

        foreach (var e in result.HarnessErrors)
            Console.Error.WriteLine($"{{\"harness-error\":\"{e.Code}\",\"subject\":\"{e.Subject}\",\"message\":\"{e.Message}\"}}");

        if (result.HarnessErrors.Count > 0)
            return (result.HarnessErrors.Count, null);

        foreach (var f in result.Failures)
            failures.Add(Failure(f.Subject, f.Code, f.Message));
        foreach (var w in result.Warnings)
            warnings.Add(Warning(w.Subject, w.Code, w.Message));

        JsonNode? metricsNode = null;
        if (result.Metrics is { } m)
        {
            metricsNode = new JsonObject
            {
                ["appliedTransitionCount"] = m.AppliedTransitionCount,
                ["successfulLogEntryCount"] = m.SuccessfulLogEntryCount,
                ["successfulLogIdCount"] = m.SuccessfulLogIdCount,
                ["duplicateSuccessLogCount"] = m.DuplicateSuccessLogCount,
                ["pendingExemptionApplied"] = m.PendingExemptionApplied,
                ["reconciliation"] = m.Reconciliation,
            };
        }

        return (0, metricsNode);
    }

    // ?꾩닔 理쒖긽??WORKSTATE ?꾨뱶瑜??뺤씤?쒕떎.
    private static void CheckRequired(JsonObject root, string property, JsonArray failures)
    {
        if (root[property] is null || string.IsNullOrWhiteSpace(root[property]?.ToString()))
            failures.Add(Failure($"workstate.{property}", "missing", "required field is absent or empty"));
    }

    // changedFiles ??ぉ ?섎굹瑜??뚯씪?쒖뒪?쑣룻빐?쒖? ?議고븳??
    private static JsonObject CheckChangedFile(string root, JsonObject item, JsonArray failures)
    {
        var path = ReadString(item, "path");
        var entry = new JsonObject
        {
            ["path"] = path,
            ["exists"] = false,
            ["hashField"] = "",
            ["hashMatches"] = null,
        };

        if (string.IsNullOrWhiteSpace(path))
        {
            failures.Add(Failure("changedFiles.path", "missing", "changedFiles item has no path"));
            return entry;
        }

        var full = Path.GetFullPath(Path.Combine(root, path));
        var insideRoot = full.Equals(root, StringComparison.OrdinalIgnoreCase)
            || full.StartsWith(root.TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar)
                + Path.DirectorySeparatorChar, StringComparison.OrdinalIgnoreCase);
        if (!insideRoot)
        {
            failures.Add(Failure(path, "outside-root", "changedFiles path escapes repository root"));
            return entry;
        }

        var exists = File.Exists(full) || Directory.Exists(full);
        entry["exists"] = exists;
        if (!exists)
        {
            failures.Add(Failure(path, "missing-file", "changedFiles path does not exist"));
            return entry;
        }

        var expectedHash = ReadString(item, "sha256");
        var hashField = "sha256";
        if (string.IsNullOrWhiteSpace(expectedHash))
        {
            expectedHash = ReadString(item, "hash");
            hashField = "hash";
        }

        entry["hashField"] = string.IsNullOrWhiteSpace(expectedHash) ? "" : hashField;
        if (string.IsNullOrWhiteSpace(expectedHash))
        {
            failures.Add(Failure(path, "missing-hash", "changedFiles item lacks sha256/hash"));
            return entry;
        }

        if (Directory.Exists(full))
        {
            failures.Add(Failure(path, "directory-hash-unsupported", "changedFiles hash can only be verified for files"));
            return entry;
        }

        var actualHash = Convert.ToHexString(SHA256.HashData(File.ReadAllBytes(full))).ToLowerInvariant();
        var normalizedExpected = expectedHash.Trim().ToLowerInvariant().Replace("sha256:", "");
        var matches = actualHash.Equals(normalizedExpected, StringComparison.OrdinalIgnoreCase);
        entry["actualSha256"] = actualHash;
        entry["hashMatches"] = matches;
        if (!matches)
            failures.Add(Failure(path, "hash-mismatch", "changedFiles hash does not match current file content"));

        return entry;
    }

    // ?꾨즺 ?곹깭??handoff媛 ?ㅼ젣 verification ?꾪떚?⑺듃瑜?媛由ы궎?붿? ?뺤씤?쒕떎.
    private static void CheckCompletionArtifacts(string root, JsonObject workstate, string diId, string status, JsonArray failures, JsonArray warnings)
    {
        if (!DoneStatuses.Contains(status)) return;

        var changed = workstate["changedFiles"] as JsonArray;
        var verificationInChangedFiles = changed?.OfType<JsonObject>()
            .Select(o => ReadString(o, "path"))
            .Any(p => p.StartsWith("docs/verification/", StringComparison.OrdinalIgnoreCase)
                && File.Exists(Path.Combine(root, p))) == true;

        var verificationById = false;
        var verificationDir = Path.Combine(root, "docs", "verification");
        if (!verificationInChangedFiles && Directory.Exists(verificationDir) && !string.IsNullOrWhiteSpace(diId))
        {
            var normalized = NormalizeId(diId);
            verificationById = Directory.EnumerateFiles(verificationDir, "*.md")
                .Any(path => NormalizeId(Path.GetFileNameWithoutExtension(path)).Contains(normalized));
        }

        if (!verificationInChangedFiles && !verificationById)
            failures.Add(Failure(diId, "missing-verification", "done status requires an existing docs/verification artifact"));
        else if (!verificationInChangedFiles)
            warnings.Add(Warning(diId, "verification-not-in-changedFiles", "verification exists by id but is not listed in current changedFiles"));
    }

    // WORKSTATE diId媛 ???뚯씪?먯꽌 ?대┛ ?곹깭?몄? ?議고븳??
    private static void CheckQueueStatus(string root, string diId, string status, JsonArray failures, JsonArray warnings)
    {
        if (string.IsNullOrWhiteSpace(diId)) return;

        var queueFiles = new[]
        {
            "docs/handoff/CODEX-QUEUE.md",
            "docs/handoff/SONNET-QUEUE.md",
        };
        var mentions = new JsonArray();
        foreach (var rel in queueFiles)
        {
            var full = Path.Combine(root, rel);
            if (!File.Exists(full)) continue;
            foreach (var line in File.ReadLines(full).Where(l => l.Contains(diId, StringComparison.OrdinalIgnoreCase)))
            {
                mentions.Add(new JsonObject
                {
                    ["queue"] = rel,
                    ["line"] = line.Trim(),
                });
                if (DoneStatuses.Contains(status) && IsOpenQueueLine(line))
                    failures.Add(Failure(rel, "queue-status-mismatch", $"{diId} is done in WORKSTATE but open in queue line"));
            }
        }

        if (mentions.Count == 0)
            warnings.Add(Warning(diId, "queue-mention-missing", "diId is not mentioned in CODEX or SONNET queue"));
    }

    // blocked ?곹깭??blockers[]媛 ?녾굅??鍮꾩뼱 ?덉쑝硫?blockers-missing, done ?곹깭??blockers[]媛 ?⑥쑝硫?blockers-stale.
    private static void CheckBlockerConsistency(JsonObject workstate, string status, JsonArray failures)
    {
        var blockers = workstate["blockers"] as JsonArray;
        var hasBlockers = blockers is not null && blockers.Count > 0;
        var blocked = status.Contains("block", StringComparison.OrdinalIgnoreCase);
        if (blocked && !hasBlockers)
            failures.Add(Failure("blockers", "blockers-missing", "blocked status requires a non-empty blockers array"));
        if (!blocked && hasBlockers && DoneStatuses.Contains(status))
            failures.Add(Failure("blockers", "blockers-stale", "done status must not carry a non-empty blockers array"));
    }

